package main

import "fmt"

// Exercises Go's nil-vs-empty distinction for DEFINED (named) slice/map/channel types — the
// sibling of SliceNilVsEmpty (which covers the plain slice<T> rows) for the go2cs-gen wrapper
// types generated by InheritedTypeTemplate. Go observes `x == nil` as REPRESENTATION nilness:
// the zero value of a named slice/map/channel is nil, but a non-nil EMPTY composite literal
// (S{}, make(...)) is observably NOT nil, and the distinction survives reslicing.
//
// The named-SLICE rows are the real regression target: the generated wrapper defines explicit
// structural Equals overloads (ISliceTypeTemplate), so its `== nil` used to compare content and
// misclassified an empty named slice as nil. The named-MAP and named-CHANNEL rows lock the audit
// finding that those wrappers were already correct (their golib backing compares by reference).
type IntSlice []int
type StrIntMap map[string]int
type IntChan chan int

func probe(name string, isNil bool) {
	fmt.Println(name, isNil)
}

func main() {
	// --- Named slice ---
	var zeroSlice IntSlice
	probe("sliceZero", zeroSlice == nil) // true — nil backing

	emptySlice := IntSlice{}
	probe("sliceEmptyLiteral", emptySlice == nil) // false — real empty backing

	madeSlice := make(IntSlice, 0)
	probe("sliceMakeZero", madeSlice == nil) // false

	filledSlice := IntSlice{1, 2}
	probe("sliceFilled", filledSlice == nil) // false

	// KEY discriminator: len 0 AND cap 0 view over a real array — still NON-nil.
	tail := filledSlice[2:2]
	probe("sliceResliceTailCapZero", tail == nil) // false

	// nil stays nil through a zero-bounds reslice.
	nilReslice := zeroSlice[0:0]
	probe("sliceNilReslice", nilReslice == nil) // true

	// --- Named map ---
	var zeroMap StrIntMap
	probe("mapZero", zeroMap == nil) // true — nil backing store

	emptyMap := StrIntMap{}
	probe("mapEmptyLiteral", emptyMap == nil) // false

	// --- Named channel ---
	var zeroChan IntChan
	probe("chanZero", zeroChan == nil) // true — nil queue

	madeChan := make(IntChan)
	probe("chanMade", madeChan == nil) // false
}
